#include <iostream>
using namespace std;
class Solution {
public:
    int leadingZeroCount(int n) {
        int count = 0;
        while (n) {
            n >>= 1;
            count++;
        }
        return count;
    }
};
int main() {
    Solution solution;
    int n;
    cin >> n;
    cout << solution.leadingZeroCount(n) << endl;
    return 0;
}
